SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_fund_mem ON sc_fund_mem CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_fund_mem() RETURNS trigger AS $BODY$
BEGIN
  BEGIN
  if coalesce(NEW.close_status::text, '') = '' or NEW.close_status = ' ' then
    NEW.close_status := '0';
  end if;
  if coalesce(NEW.total_balance::text, '') = '' then NEW.total_balance :=0;end if;

  if pka.auto_entry() then
    if coalesce(NEW.branch_id::text, '') = '' then NEW.branch_id := pka_com_function.fp_login_br;end if;

    -- เวลาที่แก้ไขล่าสุด(บังคับ)
    NEW.last_user_id := current_setting('app.login_id', true);
    NEW.last_user_date := statement_timestamp();
    NEW.last_access_date := statement_timestamp();

  end if;


  if coalesce(NEW.BEGIN_balance::text, '') = '' then NEW.BEGIN_balance := 0;end if;
  if coalesce(NEW.keep_month::text, '') = '' then NEW.keep_month := 0;end if;
  if coalesce(NEW.keep_arrear::text, '') = '' then NEW.keep_arrear :=0;end if;
  if coalesce(NEW.last_period::text, '') = '' then NEW.last_period :=0;end if;
  if coalesce(NEW.pending_amt::text, '') = '' then NEW.pending_amt :=0;end if;
  if coalesce(NEW.keep_status::text, '') = '' then NEW.keep_status :='0';end if;
  if coalesce(NEW.accu_interest::text, '') = '' then NEW.accu_interest :=0;end if;
  if coalesce(NEW.close_status::text, '') = '' then NEW.close_status :='0';end if;

  -- FUNMB=กองทุนส่วนสมาชิก ,FUNCO=กองทุนรับภาระหนี้
  if coalesce(NEW.fund_loan_no::text, '') = '' then NEW.fund_loan_no := 'FUNMB';end if;

    if coalesce(NEW.loan_type::text, '') = '' or NEW.loan_type = ' ' then
        BEGIN 
            select loan_type into STRICT NEW.loan_type
            from sc_lon_m_contract 
            where loan_contract_no = NEW.loan_contract_no;
            exception when others then null;
        end;
    end if;

  END;
RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_fund_mem() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_fund_mem
	BEFORE INSERT OR UPDATE ON sc_fund_mem FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_fund_mem();

